import React, { createContext, useContext, useEffect, useMemo, useState } from 'react';
import { ActivityIndicator, Alert, Button, SafeAreaView, StyleSheet, Text, TextInput, View } from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';

const AUTH_TOKEN_KEY = '@auth_token';
const AUTH_USER_KEY = '@auth_user';

const AuthContext = createContext(null);

export const useAuth = () => useContext(AuthContext);

async function saveAuthData(token, user) {
  await AsyncStorage.multiSet([
    [AUTH_TOKEN_KEY, token],
    [AUTH_USER_KEY, JSON.stringify(user)],
  ]);
}

async function clearAuthData() {
  await AsyncStorage.multiRemove([AUTH_TOKEN_KEY, AUTH_USER_KEY]);
}

async function loadAuthData() {
  const [[, token], [, userJson]] = await AsyncStorage.multiGet([AUTH_TOKEN_KEY, AUTH_USER_KEY]);
  return {
    token: token || null,
    user: userJson ? JSON.parse(userJson) : null,
  };
}

export function AuthProvider({ children }) {
  const [token, setToken] = useState(null);
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    let mounted = true;

    (async () => {
      try {
        const stored = await loadAuthData();
        if (mounted) {
          setToken(stored.token);
          setUser(stored.user);
        }
      } catch (e) {
        await clearAuthData();
      } finally {
        if (mounted) setLoading(false);
      }
    })();

    return () => {
      mounted = false;
    };
  }, []);

  const signIn = async ({ email, password }) => {
    const response = await fakeLoginApi(email, password);
    const nextToken = response.token;
    const nextUser = response.user;

    setToken(nextToken);
    setUser(nextUser);
    await saveAuthData(nextToken, nextUser);
  };

  const signOut = async () => {
    setToken(null);
    setUser(null);
    await clearAuthData();
  };

  const value = useMemo(
    () => ({
      token,
      user,
      loading,
      isAuthenticated: !!token,
      signIn,
      signOut,
    }),
    [token, user, loading]
  );

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
}

async function fakeLoginApi(email, password) {
  await new Promise((resolve) => setTimeout(resolve, 800));

  if (!email || !password) {
    throw new Error('Please enter email and password.');
  }

  if (password.length < 4) {
    throw new Error('Invalid credentials.');
  }

  return {
    token: `demo-token-${Date.now()}`,
    user: {
      id: 'user_1',
      name: 'Demo User',
      email,
    },
  };
}

function LoginScreen() {
  const { signIn } = useAuth();
  const [email, setEmail] = useState('demo@example.com');
  const [password, setPassword] = useState('1234');
  const [submitting, setSubmitting] = useState(false);

  const onLogin = async () => {
    try {
      setSubmitting(true);
      await signIn({ email, password });
    } catch (e) {
      Alert.alert('Login failed', e.message || 'Something went wrong.');
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <SafeAreaView style={styles.container}>
      <View style={styles.card}>
        <Text style={styles.title}>Sign In</Text>
        <TextInput
          style={styles.input}
          placeholder="Email"
          autoCapitalize="none"
          keyboardType="email-address"
          value={email}
          onChangeText={setEmail}
        />
        <TextInput
          style={styles.input}
          placeholder="Password"
          secureTextEntry
          value={password}
          onChangeText={setPassword}
        />
        {submitting ? (
          <ActivityIndicator />
        ) : (
          <Button title="Login" onPress={onLogin} />
        )}
      </View>
    </SafeAreaView>
  );
}

function HomeScreen() {
  const { user, signOut } = useAuth();

  return (
    <SafeAreaView style={styles.container}>
      <View style={styles.card}>
        <Text style={styles.title}>Welcome</Text>
        <Text style={styles.text}>Name: {user?.name}</Text>
        <Text style={styles.text}>Email: {user?.email}</Text>
        <View style={{ height: 16 }} />
        <Button title="Logout" onPress={signOut} />
      </View>
    </SafeAreaView>
  );
}

function AppNavigator() {
  const { loading, isAuthenticated } = useAuth();

  if (loading) {
    return (
      <SafeAreaView style={styles.center}>
        <ActivityIndicator size="large" />
      </SafeAreaView>
    );
  }

  return isAuthenticated ? <HomeScreen /> : <LoginScreen />;
}

export default function App() {
  return (
    <AuthProvider>
      <AppNavigator />
    </AuthProvider>
  );
}

